INSERT INTO questions (id, question, category, template_id, question_number)
VALUES
('chronic-illness-1', 'Write about the moment you realized this illness was going to be part of your life long-term. What changed in how you saw yourself that day?', 'reflection', 'chronic-illness', 1),
('chronic-illness-2', 'Think back to the past 6 months. Describe 3 specific days when you felt most like yourself despite the illness. What made those days different?', 'reflection', 'chronic-illness', 2),
('chronic-illness-3', 'Document your energy patterns over a typical week. When do you feel most capable? When does your body demand rest? What patterns emerge?', 'reflection', 'chronic-illness', 3),
('chronic-illness-4', 'Reflect on how you used to define "a good day" before your diagnosis versus now. What shifted in your measures of success?', 'reflection', 'chronic-illness', 4),
('chronic-illness-5', 'Write about a time in the past year when someone truly understood what you were going through. What did they say or do that made you feel seen?', 'reflection', 'chronic-illness', 5),
('chronic-illness-6', 'List the activities or roles that feel most threatened by your illness (parent, professional, friend, hobbyist). Which loss feels most painful right now?', 'reflection', 'chronic-illness', 6),
('chronic-illness-7', 'Think about the last time you pushed through symptoms to meet an obligation. What happened afterward? What did that teach you about your limits?', 'reflection', 'chronic-illness', 7),
('chronic-illness-8', 'Describe 3 moments in recent months when you felt proud of how you managed your illness. What were you doing? What made you feel capable?', 'reflection', 'chronic-illness', 8),
('chronic-illness-9', 'Write about how your relationship with your body has changed. When did you start seeing it as unreliable? Are there moments when you still trust it?', 'reflection', 'chronic-illness', 9),
('chronic-illness-10', 'Reflect on the people in your life right now. Who makes you feel like you have to hide or minimize your illness? Who lets you be honest about it?', 'reflection', 'chronic-illness', 10),
('chronic-illness-11', 'Document the things you''ve given up or modified because of your illness. Which adaptations feel like survival? Which feel like unnecessary surrender?', 'reflection', 'chronic-illness', 11),
('chronic-illness-12', 'Think about your identity before diagnosis. What parts of who you were do you miss most? What new parts of yourself have emerged?', 'reflection', 'chronic-illness', 12),
('chronic-illness-13', 'Write about your worst symptom day in the past month. How did you get through it? What coping strategies actually helped versus what made it worse?', 'reflection', 'chronic-illness', 13),
('chronic-illness-14', 'Reflect on how you talk about your illness to yourself in your head. Is your inner voice compassionate or critical? When did that pattern start?', 'reflection', 'chronic-illness', 14),
('chronic-illness-15', 'List the moments when your illness feels most isolating. What specifically makes you feel alone - the physical symptoms, others'' reactions, or your own thoughts?', 'reflection', 'chronic-illness', 15);
INSERT INTO questions (id, question, category, template_id, question_number)
VALUES
('chronic-illness-16', 'Track your symptoms for the next 7 days. For each day note: symptom intensity (1-10), what you ate, sleep quality, stress level, and activities. What correlations appear?', 'research', 'chronic-illness', 16),
('chronic-illness-17', 'Research 3 specialists or healthcare providers who treat your specific condition. For each, document: their approach, patient reviews, insurance coverage, and wait times for new patients.', 'research', 'chronic-illness', 17),
('chronic-illness-18', 'List every medication, supplement, and treatment you currently use. For each, note: dose, frequency, what it''s supposed to help, actual effects you notice, and side effects you experience.', 'research', 'chronic-illness', 18),
('chronic-illness-19', 'Document your last 5 medical appointments. What questions did you wish you''d asked? What information did you leave without understanding? What pattern emerges?', 'research', 'chronic-illness', 19),
('chronic-illness-20', 'Research support groups (online and local) for your specific condition. Visit or observe 3 different groups and note: tone, practical vs emotional focus, and whether you felt understood.', 'research', 'chronic-illness', 20),
('chronic-illness-21', 'Investigate disability benefits and accommodations available for your condition. What documentation would you need? What''s the application process? What would qualify you?', 'research', 'chronic-illness', 21),
('chronic-illness-22', 'List everyone on your current healthcare team (doctors, therapists, specialists). For each person, rate: how well they listen (1-10), how much you trust them, and whether they coordinate with your other providers.', 'research', 'chronic-illness', 22),
('chronic-illness-23', 'Research 5 practical aids or adaptive equipment that might help your specific symptoms. For each, note: cost, where to get it, reviews from people with your condition, and whether insurance might cover it.', 'research', 'chronic-illness', 23),
('chronic-illness-24', 'Document your insurance coverage in detail. What percentage of your medical costs are covered? What''s your out-of-pocket maximum? What treatments require pre-authorization?', 'research', 'chronic-illness', 24),
('chronic-illness-25', 'Identify 3 people you know who also live with chronic illness (any condition). What coping strategies do they use? What have they learned that you haven''t tried yet?', 'research', 'chronic-illness', 25),
('chronic-illness-26', 'Research evidence-based complementary therapies for your specific condition. For each option, note: quality of evidence, cost, accessibility in your area, and potential risks.', 'research', 'chronic-illness', 26),
('chronic-illness-27', 'List your top 3 most disruptive symptoms. For each, research: what triggers it, what relieves it, what other patients with your condition do, and what your doctor recommends.', 'research', 'chronic-illness', 27),
('chronic-illness-28', 'Document your monthly medical expenses for the past 3 months. Include: prescriptions, co-pays, equipment, over-the-counter items, and complementary treatments. What''s the pattern?', 'research', 'chronic-illness', 28);
INSERT INTO questions (id, question, category, template_id, question_number)
VALUES
('chronic-illness-29', 'Design your ideal daily routine that honors both what you need to accomplish and what your body needs. What would you do differently in the morning, afternoon, and evening?', 'planning', 'chronic-illness', 29),
('chronic-illness-30', 'Plan how you''ll explain your illness to someone new in your life (new friend, romantic interest, colleague). What do they need to know upfront? What can wait?', 'planning', 'chronic-illness', 30),
('chronic-illness-31', 'Map out your energy budget for a typical week. If you have 100 energy units total, how many go to work, family, self-care, medical appointments, and rest? What needs to change?', 'planning', 'chronic-illness', 31),
('chronic-illness-32', 'Create a communication strategy for your closest relationships. Who needs detailed updates? Who needs simple check-ins? Who do you want to protect from the details?', 'planning', 'chronic-illness', 32),
('chronic-illness-33', 'Plan for your next doctor''s appointment. What questions will you prioritize? What symptoms will you track beforehand? How will you ensure you remember what they say?', 'planning', 'chronic-illness', 33),
('chronic-illness-34', 'Design a "bad day protocol" for yourself. When symptoms flare badly, what helps? What makes it worse? What do you need from others? How will you communicate this?', 'planning', 'chronic-illness', 34),
('chronic-illness-35', 'Think about your career trajectory. What accommodations would let you continue your current path? What alternative paths might better suit your energy and symptoms?', 'planning', 'chronic-illness', 35),
('chronic-illness-36', 'Plan how to build rest and recovery into your life without feeling guilty. What boundaries need to be set? What activities need to be cut? What expectations need renegotiating?', 'planning', 'chronic-illness', 36),
('chronic-illness-37', 'Create a system for deciding when to push through symptoms versus when to rest. What factors should you consider? What are your warning signs to stop?', 'planning', 'chronic-illness', 37),
('chronic-illness-38', 'Design your support team beyond medical professionals. Who handles emotional support? Practical help? Medical advocacy? Information gathering? Who''s missing?', 'planning', 'chronic-illness', 38),
('chronic-illness-39', 'Plan how you''ll maintain the relationships that matter most despite limited energy. What low-energy ways can you stay connected? What activities need to be modified?', 'planning', 'chronic-illness', 39),
('chronic-illness-40', 'Think about disclosure at work. Who needs to know? What level of detail is appropriate? What accommodations will you request? What''s your backup plan if they react poorly?', 'planning', 'chronic-illness', 40),
('chronic-illness-41', 'Create a financial plan for managing ongoing medical costs. What can you reduce? What savings do you need? What happens if costs increase or you can''t work?', 'planning', 'chronic-illness', 41),
('chronic-illness-42', 'Design strategies for managing the emotional toll. When will you seek therapy? What daily practices support your mental health? How will you know if you''re slipping into depression?', 'planning', 'chronic-illness', 42),
('chronic-illness-43', 'Plan how to stay socially connected when you have to cancel plans frequently. How will you communicate cancellations? What alternatives can you offer? How will you handle others'' frustration?', 'planning', 'chronic-illness', 43),
('chronic-illness-44', 'Map out your priorities for the next 6 months. What absolutely must be protected? What can be delegated? What needs to be released entirely?', 'planning', 'chronic-illness', 44),
('chronic-illness-45', 'Create a contingency plan for if your condition worsens significantly. What changes would you make to work, living situation, and daily life? Who would you need to involve?', 'planning', 'chronic-illness', 45);
INSERT INTO questions (id, question, category, template_id, question_number)
VALUES
('chronic-illness-46', 'Write down the one change you could make this week that would most improve your symptom management. What''s stopping you from making it?', 'action', 'chronic-illness', 46),
('chronic-illness-47', 'Reach out to one person who has offered help but you haven''t accepted. Ask them for something specific. Document what you asked for and how it felt.', 'action', 'chronic-illness', 47),
('chronic-illness-48', 'Schedule your next medical appointment if you haven''t already. Prepare three questions you''ll ask. Set a reminder to track specific symptoms beforehand.', 'action', 'chronic-illness', 48),
('chronic-illness-49', 'Start a symptom journal today. Track for just 3 days: morning energy level, symptoms throughout the day, and what helped or hurt. Review what you learn.', 'action', 'chronic-illness', 49),
('chronic-illness-50', 'Identify one activity you''re currently doing that consistently worsens your symptoms. Plan how you''ll eliminate, modify, or delegate it.', 'action', 'chronic-illness', 50),
('chronic-illness-51', 'Create a one-page summary of your condition for new healthcare providers. Include: diagnosis, current treatments, what''s been tried before, and your key symptoms.', 'action', 'chronic-illness', 51),
('chronic-illness-52', 'Set one boundary this week that protects your energy. Tell someone "no" to something that would drain you. Notice what happens.', 'action', 'chronic-illness', 52),
('chronic-illness-53', 'Join one online community or support group for your condition. Read for a few days, then post one question or introduce yourself.', 'action', 'chronic-illness', 53),
('chronic-illness-54', 'Talk to your manager or HR about one specific accommodation that would help you work more effectively. Document what you request and their response.', 'action', 'chronic-illness', 54),
('chronic-illness-55', 'Clear your calendar of one recurring obligation that no longer serves you. Communicate the change clearly and without over-explaining.', 'action', 'chronic-illness', 55),
('chronic-illness-56', 'Organize your medications and supplements into a system that ensures you take them consistently. Set up a tracking method that works for your routine.', 'action', 'chronic-illness', 56),
('chronic-illness-57', 'Have an honest conversation with one close person about what you actually need from them. Be specific about how they can help and how they can''t.', 'action', 'chronic-illness', 57),
('chronic-illness-58', 'Research and apply for one financial resource (disability benefits, assistance program, flexible spending account) that could ease your medical costs.', 'action', 'chronic-illness', 58),
('chronic-illness-59', 'Block out specific rest time in your calendar for the next two weeks. Treat it as non-negotiable as a medical appointment.', 'action', 'chronic-illness', 59),
('chronic-illness-60', 'Write a letter to yourself for a bad symptom day. Include: reminders that it will pass, what actually helps, permission to rest, and evidence you''ve survived before.', 'action', 'chronic-illness', 60);
